#include "engine/orb/messages/InvokeMethodMessage.h"


NebulaAreaAdapter::NebulaAreaAdapter(NebulaArea* obj) : SpaceActiveAreaAdapter(obj) {
}

void NebulaAreaAdapter::invokeMethod(uint32 methid, DistributedMethod* inv) {
	DOBMessage* resp = inv->getInvocationMessage();

	switch (methid) {
	case RPC_SETNEBULADENSITY__FLOAT_:
		{
			float density = inv->getFloatParameter();
			
			setNebulaDensity(density);
			
		}
		break;
	case RPC_SETAMBIENTSOUND__STRING_:
		{
			 String sound; inv->getAsciiParameter(sound);
			
			setAmbientSound(sound);
			
		}
		break;
	case RPC_SETLIGHTNINGAPPEARANCE__STRING_:
		{
			 String appearance; inv->getAsciiParameter(appearance);
			
			setLightningAppearance(appearance);
			
		}
		break;
	case RPC_SETLIGHTNINGSOUND__STRING_:
		{
			 String sound; inv->getAsciiParameter(sound);
			
			setLightningSound(sound);
			
		}
		break;
	case RPC_SETLIGHTNINGSOUNDLOOP__STRING_:
		{
			 String sound; inv->getAsciiParameter(sound);
			
			setLightningSoundLoop(sound);
			
		}
		break;
	case RPC_SETLIGHTNINGHITEFFECTCLIENT__STRING_:
		{
			 String effect; inv->getAsciiParameter(effect);
			
			setLightningHitEffectClient(effect);
			
		}
		break;
	case RPC_SETLIGHTNINGHITEFFECTSERVER__STRING_:
		{
			 String effect; inv->getAsciiParameter(effect);
			
			setLightningHitEffectServer(effect);
			
		}
		break;
	case RPC_SETLIGHTNINGDAMAGEMIN__FLOAT_:
		{
			float damage = inv->getFloatParameter();
			
			setLightningDamageMin(damage);
			
		}
		break;
	case RPC_SETLIGHTNINGDAMAGEMAX__FLOAT_:
		{
			float damage = inv->getFloatParameter();
			
			setLightningDamageMax(damage);
			
		}
		break;
	case RPC_SETLIGHTNINGFREQUENCY__INT_:
		{
			int frequency = inv->getSignedIntParameter();
			
			setLightningFrequency(frequency);
			
		}
		break;
	case RPC_SETLIGHTNINGDURATIONMAX__INT_:
		{
			int maxDuration = inv->getSignedIntParameter();
			
			setLightningDurationMax(maxDuration);
			
		}
		break;
	case RPC_SETNEBULAID__INT_:
		{
			int nebulaId = inv->getSignedIntParameter();
			
			setNebulaID(nebulaId);
			
		}
		break;
	case RPC_GETNEBULADENSITY__:
		{
			
			float _m_res = getNebulaDensity();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETMAXLIGHTNINGDURATION__:
		{
			
			float _m_res = getMaxLightningDuration();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETNEBULAID__:
		{
			
			int _m_res = getNebulaID();
			resp->insertSignedInt(_m_res);
		}
		break;
	case RPC_GETLIGHTNINGDAMAGEMIN__:
		{
			
			float _m_res = getLightningDamageMin();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_GETLIGHTNINGDAMAGEMAX__:
		{
			
			float _m_res = getLightningDamageMax();
			resp->insertFloat(_m_res);
		}
		break;
	case RPC_NOTIFYPOSITIONUPDATE__TREEENTRY_:
		{
			TreeEntry* entry = static_cast<TreeEntry*>(inv->getObjectParameter());
			
			notifyPositionUpdate(entry);
			
		}
		break;
	case RPC_NOTIFYENTER__SCENEOBJECT_:
		{
			SceneObject* object = static_cast<SceneObject*>(inv->getObjectParameter());
			
			notifyEnter(object);
			
		}
		break;
	case RPC_NOTIFYEXIT__SCENEOBJECT_:
		{
			SceneObject* object = static_cast<SceneObject*>(inv->getObjectParameter());
			
			notifyExit(object);
			
		}
		break;
	default:
		SpaceActiveAreaAdapter::invokeMethod(methid, inv);
	}
}

